-- ----------------------------
-- Table structure for user_ticket
-- ----------------------------
DROP TABLE IF EXISTS `user_ticket`;
CREATE TABLE `user_ticket`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int(11) NOT NULL COMMENT '用户ID，关联user表',
  `order_id` int(11) NOT NULL COMMENT '订单ID，关联orders表',
  `ticket_id` int(11) NOT NULL COMMENT '票务ID，关联ticket表',
  `exhibition_id` int(11) NOT NULL COMMENT '漫展ID，关联exhibition表',
  `status` int(2) NOT NULL DEFAULT 0 COMMENT '状态：0未使用，1已使用，2已退款,3已取消',
  `use_time` datetime(0) NULL DEFAULT NULL COMMENT '使用时间（核销时间）',
  `verify_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '123456' COMMENT '核销码（唯一）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_verify_code`(`verify_code`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_order_id`(`order_id`) USING BTREE,
  INDEX `idx_ticket_id`(`ticket_id`) USING BTREE,
  INDEX `idx_exhibition_id`(`exhibition_id`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 36 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户票务表（核销记录）' ROW_FORMAT = Dynamic;

